@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    @{
        var groups = GetGroups();
        for (var g = 0; g < groups.Count; g++)
        {
            var group = groups[g];
            <div class="flex items-center gap-2">
                @foreach (var idx in group)
                {
                    var index = idx;
                    <input @key="@($"{index}:{GetChar(index)}:{_cellNonce[index]}")"
                           id="@($"{_baseId}-{index}")"
                           aria-required="@Required.ToString().ToLowerInvariant()"
                           aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
                           aria-describedby="@(index == 0 ? FormFieldDescribedBy : null)"
                           aria-label="@(string.Format(L["OtpInput.DigitLabel"], index + 1, Length))"
                           type="@(Masked ? "password" : "text")"
                           inputmode="@InputModeAttr"
                           maxlength="1"
                           autocomplete="one-time-code"
                           class="@($"flex h-10 w-10 items-center justify-center rounded-md border {(EffectiveInvalid ? "border-destructive focus-visible:ring-[1.5px] focus-visible:ring-destructive/20" : "border-input")} bg-transparent text-center text-sm font-medium transition-colors focus-visible:outline-none disabled:cursor-not-allowed disabled:opacity-50")"
                           disabled="@Disabled"
                           value="@GetChar(index)"
                           @oninput="@(e => HandleInput(index, e))"
                           @onkeydown="@(e => HandleKeyDown(index, e))"
                           @onkeydown:stopPropagation="true" />
                }
            </div>
            @if (g < groups.Count - 1 && Separator is not null)
            {
                <span class="text-muted-foreground text-lg font-medium px-1">@Separator</span>
            }
        }
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@implements IAsyncDisposable
@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public int Length { get; set; } = 6;
    [Parameter] public string Value { get; set; } = "";
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    [Parameter] public EventCallback<string> OnComplete { get; set; }
    [Parameter] public string InputMode { get; set; } = "Numeric";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Masked { get; set; }
    [Parameter] public string? Separator { get; set; }
    [Parameter] public int[]? GroupSizes { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    /// <summary>Focuses the first OTP digit input on first render. Useful
    /// for the typical OTP flow where the field appears right after a
    /// "code sent" screen and the user should be typing immediately.
    /// See <c>Input.AutoFocus</c> for why the HTML <c>autofocus</c>
    /// attribute doesn't work in Blazor WASM.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>Programmatically move focus to the first digit input.</summary>
    public ValueTask FocusAsync() => Interop.FocusElement($"{_baseId}-0");

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Point aria-describedby at the FormField's rendered help/error text so a screen
    // reader announces it on the first OTP box (null outside a FormField). The boxes keep
    // their own generated ids (load-bearing for focus/paste JS interop), so the FormField
    // <Label For> can't click-focus them — but the aria-describedby association is the win.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    private readonly string _baseId = LumeoIds.New("otp");

    // Per-cell render nonce. Bumping a cell's nonce changes that input's @key so
    // Blazor recreates the element with its model value — used to discard a
    // rejected keystroke that the browser already painted (#178), without
    // re-keying the other cells (which would steal focus).
    private int[] _cellNonce = System.Array.Empty<int>();

    protected override void OnParametersSet()
    {
        if (Length < 0)
            throw new ArgumentOutOfRangeException(nameof(Length), "Length cannot be negative.");

        if (_cellNonce.Length != Length)
            _cellNonce = new int[Length];
    }

    private string CssClass => Cx.Merge("flex items-center gap-2", Class);

    private string InputModeAttr => InputMode switch
    {
        "Alphanumeric" => "text",
        "Password" => "text",
        _ => "numeric"
    };

    private List<List<int>> GetGroups()
    {
        var groups = new List<List<int>>();
        if (GroupSizes is not null && GroupSizes.Length > 0)
        {
            var idx = 0;
            foreach (var size in GroupSizes)
            {
                var group = new List<int>();
                for (var i = 0; i < size && idx < Length; i++, idx++)
                {
                    group.Add(idx);
                }
                if (group.Count > 0) groups.Add(group);
            }
            // Handle any remaining inputs not covered by GroupSizes
            if (idx < Length)
            {
                var remaining = new List<int>();
                for (; idx < Length; idx++) remaining.Add(idx);
                groups.Add(remaining);
            }
        }
        else
        {
            var all = new List<int>();
            for (var i = 0; i < Length; i++) all.Add(i);
            groups.Add(all);
        }
        return groups;
    }

    private string GetChar(int index) => index < Value.Length ? Value[index].ToString() : "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterOtpPaste(_baseId, Length, HandlePaste);
            if (AutoFocus)
            {
                await Interop.FocusElement($"{_baseId}-0");
            }
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    private async Task HandlePaste(string text)
    {
        var filtered = FilterInput(text);
        // Truncate to capacity; do NOT pad — padding produced trailing/interior
        // whitespace that leaked into the surfaced value (#178).
        Value = filtered.Length > Length ? filtered[..Length] : filtered;
        await ValueChanged.InvokeAsync(Value);

        if (Value.Length == Length)
        {
            await OnComplete.InvokeAsync(Value);
        }
        else if (Value.Length > 0)
        {
            await Interop.FocusElement($"{_baseId}-{Value.Length}");
        }
    }

    private bool IsValidChar(char c) => InputMode switch
    {
        "Numeric" => char.IsDigit(c),
        "Alphanumeric" => char.IsLetterOrDigit(c),
        _ => true // Password mode allows any character
    };

    private string FilterInput(string input)
    {
        return new string(input.Where(IsValidChar).ToArray());
    }

    // Editing buffer of fixed Length. Empty cells use the NUL sentinel rather
    // than a space, so they never surface as whitespace in the emitted value.
    private const char Empty = '\0';

    private char[] CellsFromValue()
    {
        var cells = new char[Length];
        for (var i = 0; i < Length; i++)
            cells[i] = i < Value.Length ? Value[i] : Empty;
        return cells;
    }

    // Collapse the buffer to a clean, gap-free string. Interior empties (e.g. a
    // mid-field clear) contribute nothing, so the value is never space-padded.
    private static string BuildValue(char[] cells)
        => new(cells.Where(c => c != Empty).ToArray());

    private async Task HandleInput(int index, ChangeEventArgs e)
    {
        var input = e.Value?.ToString() ?? "";
        if (input.Length == 0)
            return;

        var lastChar = input[^1];
        if (!IsValidChar(lastChar))
        {
            // The browser already painted the rejected character. Bumping this
            // cell's nonce re-keys only this input so Blazor recreates it from the
            // model value, instantly discarding the invalid char (#178). Recreating
            // the element drops focus, so restore it to the same cell.
            _cellNonce[index]++;
            StateHasChanged();
            try { await Interop.FocusElement($"{_baseId}-{index}"); }
            catch (JSDisconnectedException) { }
            return;
        }

        var cells = CellsFromValue();
        cells[index] = lastChar;
        Value = BuildValue(cells);
        await ValueChanged.InvokeAsync(Value);

        if (index < Length - 1)
        {
            await Interop.FocusElement($"{_baseId}-{index + 1}");
        }

        if (Value.Length == Length)
        {
            await OnComplete.InvokeAsync(Value);
        }
    }

    private async Task HandleKeyDown(int index, KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowLeft":
                if (index > 0)
                    await Interop.FocusElement($"{_baseId}-{index - 1}");
                return;
            case "ArrowRight":
                if (index < Length - 1)
                    await Interop.FocusElement($"{_baseId}-{index + 1}");
                return;
            case "Home":
                await Interop.FocusElement($"{_baseId}-0");
                return;
            case "End":
                await Interop.FocusElement($"{_baseId}-{Length - 1}");
                return;
            case "Delete":
                // Forward-delete: clear ONLY the current cell and keep focus
                // here (do not collapse to the previous box like Backspace).
                // On an already-empty cell, do nothing.
                if (GetChar(index) != "")
                {
                    var deleteCells = CellsFromValue();
                    deleteCells[index] = Empty;
                    Value = BuildValue(deleteCells);
                    await ValueChanged.InvokeAsync(Value);
                }
                return;
            case "Backspace":
                break;
            default:
                return;
        }

        // Backspace: clear the current cell (or, when empty, the previous one)
        // and move focus backward.
        var cells = CellsFromValue();
        if (GetChar(index) != "")
        {
            cells[index] = Empty;
            Value = BuildValue(cells);
            await ValueChanged.InvokeAsync(Value);
            if (index > 0)
                await Interop.FocusElement($"{_baseId}-{index - 1}");
        }
        else if (index > 0)
        {
            cells[index - 1] = Empty;
            Value = BuildValue(cells);
            await ValueChanged.InvokeAsync(Value);
            await Interop.FocusElement($"{_baseId}-{index - 1}");
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await Interop.UnregisterOtpPaste(_baseId, Length);
        }
        catch (JSDisconnectedException) { }
    }
}
